		if u.Scheme != "https" {
			return "", fmt.Errorf("raw absolute URLs must use https")
		}
		if !client.IsAllowedAbsoluteHost(u.Hostname()) {
			return "", fmt.Errorf("raw absolute URL host %q is not in the x.com/api.x.com/upload.x.com allowlist", u.Hostname())
		}
		return raw, nil
